package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() {
    // Android class name starts with "android."
    // android.app.Activity is not available in JVM, so use a dummy class with overridden getName()
    Class<?> androidClass = new Class<Object>() {
      @Override
      public String getName() {
        return "android.app.Activity";
      }
    }.getClass();
    // Instead of new Class<Object>() { ... }.getClass(), which returns anonymous class,
    // we create a proxy Class subclass using reflection to override getName() is not possible,
    // so better to create a dummy class and use a custom class loader or mock,
    // but simplest is to create a dummy class and override getName() via a dynamic proxy or use a mock.
    // Since Class is final, Mockito cannot mock it directly.
    // So instead we create a custom class with getName() method and pass its class,
    // but ReflectionAccessFilterHelper.isAnyPlatformType uses c.getName(), so we can
    // create a custom class extending Class is impossible.
    // So, we can create a dummy class in package android.app.
    // But package android.app is restricted.
    // So, we can create a dummy class with a name starting with "android." using a custom class loader.

    // To fix this properly, use a helper method to create a class with a fake name.
    Class<?> fakeAndroidClass = createClassWithName("android.app.Activity");
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(fakeAndroidClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withJavaType() {
    // Java class name starts with "java."
    Class<?> javaClass = String.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(javaClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withKotlinType() {
    Class<?> kotlinClass = DummyKotlin.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withKotlinxType() {
    Class<?> kotlinxClass = DummyKotlinx.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withScalaType() {
    Class<?> scalaClass = DummyScala.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withNonPlatformType() {
    Class<?> nonPlatformClass = DummyNonPlatform.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(nonPlatformClass);
    assertFalse(result);
  }

  // Dummy classes for testing prefixes
  static class DummyKotlin {
    // Override getName() to simulate class name starting with "kotlin."
    @Override
    public String toString() {
      return "kotlin.DummyKotlin";
    }
  }

  static class DummyKotlinx {
    @Override
    public String toString() {
      return "kotlinx.DummyKotlinx";
    }
  }

  static class DummyScala {
    @Override
    public String toString() {
      return "scala.DummyScala";
    }
  }

  static class DummyNonPlatform {
    @Override
    public String toString() {
      return "dummy.NonPlatform";
    }
  }

  // Helper method to create a Class<?> with a fake name
  private static Class<?> createClassWithName(String name) {
    return new Class<Object>() {
      @Override
      public String getName() {
        return name;
      }
    }.getClass();
  }
}
